import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Layout from '../components/shared/Layout';
import { campaignAPI } from '../utils/api';
import { PlatformIcons, PLATFORMS, CAMPAIGN_OBJECTIVES, formatKPI } from '../utils/platforms';

const STATUS_OPTIONS = ['all', 'active', 'paused', 'draft', 'completed'];

export default function CampaignsPage() {
  const navigate = useNavigate();
  const [campaigns, setCampaigns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [search, setSearch] = useState('');

  const fetchCampaigns = async () => {
    try {
      const params = {};
      if (filter !== 'all') params.status = filter;
      const res = await campaignAPI.getAll(params);
      setCampaigns(res.data.campaigns || []);
    } catch {
      setCampaigns(MOCK_CAMPAIGNS);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchCampaigns(); }, [filter]);

  const filtered = campaigns.filter(c =>
    c.name.toLowerCase().includes(search.toLowerCase())
  );

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this campaign?')) return;
    await campaignAPI.delete(id).catch(() => {});
    setCampaigns(prev => prev.filter(c => c._id !== id));
  };

  return (
    <Layout>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 28 }}>
        <div>
          <h1 style={{ fontFamily: 'Syne', fontSize: 28, fontWeight: 800, color: '#e8e0f5', margin: '0 0 6px' }}>Campaigns</h1>
          <p style={{ color: '#8b7baa', margin: 0, fontSize: 14 }}>{filtered.length} campaigns total</p>
        </div>
        <button className="btn-primary" onClick={() => navigate('/campaigns/new')}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 5v14M5 12h14"/></svg>
          New Campaign
        </button>
      </div>

      {/* Filters */}
      <div style={{ display: 'flex', gap: 12, marginBottom: 20, flexWrap: 'wrap' }}>
        <input
          className="form-input"
          placeholder="🔍 Search campaigns..."
          value={search}
          onChange={e => setSearch(e.target.value)}
          style={{ maxWidth: 280 }}
        />
        <div style={{ display: 'flex', gap: 6 }}>
          {STATUS_OPTIONS.map(s => (
            <button
              key={s}
              onClick={() => setFilter(s)}
              style={{
                padding: '8px 16px', borderRadius: 8, fontSize: 12, fontWeight: 600, cursor: 'pointer',
                textTransform: 'capitalize',
                background: filter === s ? 'rgba(124,58,237,0.2)' : 'transparent',
                border: `1px solid ${filter === s ? 'rgba(124,58,237,0.5)' : 'rgba(139,92,246,0.15)'}`,
                color: filter === s ? '#c084fc' : '#6b7280', transition: 'all 0.2s'
              }}
            >
              {s}
            </button>
          ))}
        </div>
      </div>

      {/* Campaign table */}
      {loading ? (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          {[...Array(4)].map((_, i) => <div key={i} className="skeleton" style={{ height: 80, borderRadius: 12 }} />)}
        </div>
      ) : filtered.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '60px 20px', color: '#6b7280' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>📭</div>
          <div style={{ fontSize: 16, fontWeight: 600, marginBottom: 8, color: '#8b7baa' }}>No campaigns found</div>
          <button className="btn-primary" onClick={() => navigate('/campaigns/new')}>Create your first campaign</button>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          {filtered.map(campaign => {
            const obj = CAMPAIGN_OBJECTIVES.find(o => o.id === campaign.objective);
            const totalSpent = (campaign.platforms || []).reduce((s, p) => s + (p.metrics?.amountSpent || 0), 0);
            const totalImpressions = (campaign.platforms || []).reduce((s, p) => s + (p.metrics?.impressions || 0), 0);

            return (
              <div
                key={campaign._id}
                className="glass-card"
                style={{ padding: '20px 24px', display: 'grid', gridTemplateColumns: '2fr 1fr 1fr 1fr auto', gap: 20, alignItems: 'center', cursor: 'pointer', transition: 'all 0.2s' }}
                onClick={() => navigate(`/campaigns/${campaign._id}`)}
              >
                {/* Name + objective */}
                <div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 8 }}>
                    <span style={{ fontSize: 15, fontWeight: 700, color: '#e8e0f5' }}>{campaign.name}</span>
                    <span className={`status-${campaign.status}`} style={{ padding: '2px 10px', borderRadius: 20, fontSize: 11, fontWeight: 700 }}>
                      {campaign.status}
                    </span>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                    <span style={{ fontSize: 12, color: '#8b7baa' }}>{obj?.icon} {obj?.label}</span>
                    <div style={{ display: 'flex', gap: 6 }}>
                      {(campaign.platforms || []).map(p => {
                        const Icon = PlatformIcons[p.platform];
                        return Icon ? <Icon key={p.platform} size={16} /> : null;
                      })}
                    </div>
                  </div>
                </div>

                {/* Budget */}
                <div>
                  <div style={{ fontSize: 11, color: '#6b7280', marginBottom: 4 }}>Total Budget</div>
                  <div style={{ fontSize: 15, fontWeight: 700, color: '#e8e0f5' }}>
                    ${(campaign.totalBudget || 0).toFixed(0)}
                  </div>
                </div>

                {/* Spent */}
                <div>
                  <div style={{ fontSize: 11, color: '#6b7280', marginBottom: 4 }}>Amount Spent</div>
                  <div style={{ fontSize: 15, fontWeight: 700, color: '#c084fc' }}>
                    {formatKPI(totalSpent, 'currency')}
                  </div>
                </div>

                {/* Impressions */}
                <div>
                  <div style={{ fontSize: 11, color: '#6b7280', marginBottom: 4 }}>Impressions</div>
                  <div style={{ fontSize: 15, fontWeight: 700, color: '#e8e0f5' }}>
                    {formatKPI(totalImpressions, 'number')}
                  </div>
                </div>

                {/* Actions */}
                <div style={{ display: 'flex', gap: 8 }} onClick={e => e.stopPropagation()}>
                  <button
                    onClick={() => navigate(`/campaigns/${campaign._id}/edit`)}
                    style={{ background: 'rgba(124,58,237,0.1)', border: '1px solid rgba(124,58,237,0.3)', color: '#c084fc', borderRadius: 8, padding: '7px 12px', cursor: 'pointer', fontSize: 12 }}
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDelete(campaign._id)}
                    style={{ background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.3)', color: '#ef4444', borderRadius: 8, padding: '7px 12px', cursor: 'pointer', fontSize: 12 }}
                  >
                    Del
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </Layout>
  );
}

const MOCK_CAMPAIGNS = [
  {
    _id: '1', name: 'Q4 Brand Awareness Drive', objective: 'awareness', status: 'active',
    totalBudget: 5000,
    platforms: [
      { platform: 'meta', metrics: { amountSpent: 1200, impressions: 85000 } },
      { platform: 'google', metrics: { amountSpent: 800, impressions: 62000 } },
      { platform: 'tiktok', metrics: { amountSpent: 500, impressions: 130000 } }
    ]
  },
  {
    _id: '2', name: 'Summer Sale Conversions', objective: 'conversions', status: 'active',
    totalBudget: 8000,
    platforms: [
      { platform: 'meta', metrics: { amountSpent: 3200, impressions: 210000 } },
      { platform: 'linkedin', metrics: { amountSpent: 1800, impressions: 45000 } }
    ]
  },
  {
    _id: '3', name: 'App Install Campaign', objective: 'app_installs', status: 'paused',
    totalBudget: 3000,
    platforms: [
      { platform: 'tiktok', metrics: { amountSpent: 900, impressions: 95000 } },
      { platform: 'snapchat', metrics: { amountSpent: 450, impressions: 67000 } }
    ]
  },
  {
    _id: '4', name: 'Lead Gen - Finance Sector', objective: 'lead_generation', status: 'draft',
    totalBudget: 2500,
    platforms: [
      { platform: 'linkedin', metrics: { amountSpent: 0, impressions: 0 } },
      { platform: 'twitter', metrics: { amountSpent: 0, impressions: 0 } }
    ]
  }
];
